import React from 'react';
import './style.css';
function Footer() {
  return (
    <footer className="fixed-footer">
      <div className="footer-shell">
        <div>
          <p className="footer-brand">React Atelier</p>
          <p className="footer-note">A polished practice app for routing, state, and UI work.</p>
        </div>
        <p className="footer-copy">copyright &copy; 2024 Alara Programming.</p>
      </div>
    </footer>
  );
}
export default Footer;
